def ConnectionPool(max_size=5):
    import threading
    from collections import deque

    class Connection:
        _counter = 0
        _lock = threading.Lock()

        def __init__(self):
            with Connection._lock:
                Connection._counter += 1
                self.id = Connection._counter
            self.closed = False

        def execute(self, query):
            if self.closed:
                raise RuntimeError('Connection is closed')
            return f'Result of {query} on conn {self.id}'

        def close(self):
            self.closed = True

    class _Pool:
        def __init__(self, max_size=5):
            if max_size is None or max_size <= 0:
                raise ValueError("max_size must be a positive integer")
            self.max_size = max_size
            self._pool = deque()
            self._in_use = set()
            self._lock = threading.Lock()
            self._current_conn = None
            for _ in range(max_size):
                self._pool.append(Connection())

        def acquire(self):
            with self._lock:
                if not self._pool:
                    raise RuntimeError('No connections available')
                conn = self._pool.popleft()
                self._in_use.add(conn)
                return conn

        def release(self, conn):
            if conn is None:
                return
            with self._lock:
                if conn in self._in_use:
                    self._in_use.remove(conn)
                    self._pool.append(conn)

        def __enter__(self):
            self._current_conn = self.acquire()
            return self._current_conn

        def __exit__(self, exc_type, exc_val, exc_tb):
            # Always release the connection regardless of exceptions to avoid leaks
            conn = getattr(self, "_current_conn", None)
            try:
                if conn is not None:
                    self.release(conn)
            finally:
                self._current_conn = None
            # Do not suppress exceptions
            return False

        @property
        def available(self):
            with self._lock:
                return len(self._pool)

        @property
        def in_use_count(self):
            with self._lock:
                return len(self._in_use)

    return _Pool(max_size)

